// PWA 的精神：把抓過的資源「快取」起來，沒網路時照樣拿得到
const cache = {};

function fetchWithCache(url, online) {
  if (online) {
    cache[url] = "（從網路抓到的最新內容）";
    return "🌐 線上：" + cache[url] + " ← 順便存進快取";
  }
  // 沒網路 → 從快取拿（這就是 Service Worker 在背景做的事）
  return cache[url]
    ? "📦 離線：" + cache[url] + "（來自快取）"
    : "❌ 離線又沒快取，拿不到";
}

console.log(fetchWithCache("/home", true));    // 線上：先抓、順便快取
console.log(fetchWithCache("/home", false));   // 斷網：也能從快取拿到

