## App Shell
UI 框架先 cache：
```javascript
const SHELL = ["/", "/style.css", "/app.js", "/offline.html"];

self.addEventListener("install", (event) => {
  event.waitUntil(
    caches.open("shell-v1").then(cache => cache.addAll(SHELL))
  );
});
```

## Offline Fallback
```javascript
self.addEventListener("fetch", (event) => {
  event.respondWith(
    fetch(event.request).catch(() => {
      if (event.request.mode === "navigate") {
        return caches.match("/offline.html");
      }
      return caches.match(event.request);
    })
  );
});
```

## IndexedDB（結構化資料）
```javascript
import { openDB } from "idb";

const db = await openDB("my-app", 1, {
  upgrade(db) {
    db.createObjectStore("posts", { keyPath: "id" });
  }
});

await db.put("posts", { id: "1", title: "..." });
const post = await db.get("posts", "1");
const all = await db.getAll("posts");
```

## Background Sync
```javascript
// user submit、沒網路
async function submitPost(post) {
  try {
    await fetch("/api/posts", { method: "POST", body: JSON.stringify(post) });
  } catch {
    await db.put("pending-posts", post);
    const reg = await navigator.serviceWorker.ready;
    await reg.sync.register("sync-posts");
  }
}

// sw.js
self.addEventListener("sync", (event) => {
  if (event.tag === "sync-posts") {
    event.waitUntil(syncPosts());
  }
});

async function syncPosts() {
  const pending = await db.getAll("pending-posts");
  for (const post of pending) {
    await fetch("/api/posts", { method: "POST", body: JSON.stringify(post) });
    await db.delete("pending-posts", post.id);
  }
}
```

## 偵測網路
```javascript
window.addEventListener("online", () => console.log("connected"));
window.addEventListener("offline", () => console.log("disconnected"));

if (navigator.onLine) { /* ... */ }
```

## UI 反饋
```jsx
function OfflineBanner() {
  const [online, setOnline] = useState(navigator.onLine);
  useEffect(() => {
    const goOnline = () => setOnline(true);
    const goOffline = () => setOnline(false);
    window.addEventListener("online", goOnline);
    window.addEventListener("offline", goOffline);
    return () => {
      window.removeEventListener("online", goOnline);
      window.removeEventListener("offline", goOffline);
    };
  }, []);
  if (online) return null;
  return <div>離線中、變更會自動同步</div>;
}
```

## 樂觀更新
寫入立刻顯示 + 背景 sync。

**☕ 用人話講**

離線 + Background Sync：讓 App **沒網路也能用、有網路時自動把資料同步回伺服器**。**一句話記住**：像離線記事——在地鐵沒訊號時照樣能寫，出站一有網路就自動上傳，整個過程使用者完全無感、不會掉資料。

